INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Keg_Load','Keg Load','espalda baja',ARRAY['abdominales','bíceps','pantorrillas','antebrazos','glúteos','isquiotibiales','espalda media','cuádriceps','hombros','trapecios'],'otro','strongman',ARRAY['To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet.','Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest.','The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible.','Return to the starting position to retrieve the next keg, and repeat until the event is completed.'],'To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet. Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest. The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Return to the starting position to retrieve the next keg, and repeat until the event is completed.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Keg_Load/0.jpg','exercisedb',true),('Kettlebell_Arnold_Press','Kettlebell Arnold Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward.','Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion.','Return the kettlebell to the starting position, with the palm facing in.'],'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward. Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion. Return the kettlebell to the starting position, with the palm facing in.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Arnold_Press/0.jpg','exercisedb',true),('Kettlebell_Dead_Clean','Kettlebell Dead Clean','isquiotibiales',ARRAY['pantorrillas','glúteos','espalda baja','cuádriceps','trapecios'],'kettlebells','strength',ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.'],'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead. Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Dead_Clean/0.jpg','exercisedb',true),('Kettlebell_Figure_8','Kettlebell Figure 8','abdominales',ARRAY['isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.'],'Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat. Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Figure_8/0.jpg','exercisedb',true),('Kettlebell_Hang_Clean','Kettlebell Hang Clean','isquiotibiales',ARRAY['pantorrillas','glúteos','espalda baja','hombros','trapecios'],'kettlebells','strength',ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower kettlebell to a hanging position between your legs while keeping the hamstrings loaded. Keep your head up at all times.'],'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead. Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. Lower kettlebell to a hanging position between your legs while keeping the hamstrings loaded. Keep your head up at all times.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Hang_Clean/0.jpg','exercisedb',true),('Kettlebell_One-Legged_Deadlift','Kettlebell One-Legged Deadlift','isquiotibiales',ARRAY['glúteos','espalda baja'],'kettlebells','strength',ARRAY['Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell.','Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance.','Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.'],'Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell. Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance. Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_One-Legged_Deadlift/0.jpg','exercisedb',true),('Kettlebell_Pass_Between_The_Legs','Kettlebell Pass Between The Legs','abdominales',ARRAY['glúteos','isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.'],'Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat. Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pass_Between_The_Legs/0.jpg','exercisedb',true),('Kettlebell_Pirate_Ships','Kettlebell Pirate Ships','hombros',ARRAY['abdominales'],'kettlebells','strength',ARRAY['With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.','Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.','Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height.','Repeat for the desired amount of repetitions.'],'With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position. Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion. Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height. Repeat for the desired amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pirate_Ships/0.jpg','exercisedb',true),('Kettlebell_Pistol_Squat','Kettlebell Pistol Squat','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other.','Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you.','Hold the bottom position for a second and then reverse the motion, driving through the heel and keeping your head and chest up.','Lower yourself again and repeat.'],'Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other. Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you. Hold the bottom position for a second and then reverse the motion, driving through the heel and keeping your head and chest up. Lower yourself again and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pistol_Squat/0.jpg','exercisedb',true),('Kettlebell_Seated_Press','Kettlebell Seated Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Sit on the floor and spread your legs out comfortably.','Clean one kettlebell to your shoulder.','Press the kettlebell up and out until it is locked out overhead. Return to the starting position.'],'Sit on the floor and spread your legs out comfortably. Clean one kettlebell to your shoulder. Press the kettlebell up and out until it is locked out overhead. Return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seated_Press/0.jpg','exercisedb',true);